def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = ratio ** 3
        elif 0.5 < ratio <= 1:
            priorities[i] = (1 - ratio) * 10 + np.log(capacity + 1)
        else:
            score = 0
            for j in range(1, int(capacity)+1):
                if j % 2 == 0:
                    score += np.sqrt(j)
                else:
                    score -= np.log(j + 1)
            priorities[i] = score / (capacity + 1) + ratio * 5
    max_priority = np.max(priorities[np.isfinite(priorities)])
    priorities[priorities == np.inf] = max_priority * 10
    return priorities
